import {AfterViewInit, ChangeDetectionStrategy, ChangeDetectorRef, Component, HostListener, OnInit} from '@angular/core';

declare var data : any;

@Component({
    selector: 'app-about',
    templateUrl: './about.component.html',
    changeDetection: ChangeDetectionStrategy.OnPush,
    styleUrls: ['./about.component.css'],
    standalone: false
})

export class AboutComponent implements OnInit,AfterViewInit {
	public aboutData = data["About"];
	public activeTab = "story";
	public selector : any;

	public activeElements : any = {};

	constructor(public changeDetectorRef: ChangeDetectorRef) {
		changeDetectorRef.detach();
	}

	ngOnInit(): void {
		this.changeDetectorRef.detectChanges();
	}
	ngAfterViewInit() {
		for(const tab of this.aboutData['NavTabs']){
			if(!this.activeElements[tab.id]){
				this.activeElements[tab.id] = document.getElementById(tab.id+'-tab')!!;
			}
			this.activeElements[tab.id].addEventListener('click',(event : any) => event.preventDefault());
		}

		this.changeActiveTab(this.activeTab);
	}

	@HostListener('window:resize', ['$event'])
	onWindowResize() {
		this.updateSelector(this.activeTab);
	}

	public changeActiveTab(tab : string) {
		this.updateSelector(tab);
		this.activeTab = tab;
		this.changeDetectorRef.detectChanges();
	}

	public updateSelector(tab : string) {
		if(!this.selector){
			this.selector = document.getElementById('selector');
		}
		this.selector.style.width = `${this.activeElements[tab].offsetWidth}px`;
		this.selector.style.left = `${this.activeElements[tab].offsetLeft}px`;
	}
}
<section class="section" id="about"><div class="container"><div class="row justify-content-center txt-bg txt-bg-about"><div class="col-lg-6 pointer"><div class="wow fadeIn section-title text-center mb-4 pb-2"><div class="mb-5 pb-3"><i class="fas fa-user-graduate h1 text-muted"></i></div><h2 class="h3 font-weight-bold">About me</h2><p class="text-muted mx-auto mb-0 mt-4 para-desc">Experience, technologies and background.</p></div></div></div><div class="col-lg-12 mt-4 pt-2"><ul class="nav-tabs nav-fill" id="myTab"><li id="selector"></li><li *ngFor="let tab of aboutData['NavTabs']" class="nav-item" (click)="changeActiveTab(tab['id'])"><ng-template #title><strong><em>{{ tab['name'] }}</em></strong></ng-template><a href="/" rel="noreferrer" class="nav-link" [ngClass]="{'active': activeTab === tab['id']}" id="{{tab['id']}}-tab" placement="{{tab['placement']}}" [ngbTooltip]="title"> {{tab["name"] }} </a></li></ul><div class="tab-content" id="myTabContent"><div class="tab-pane fade" [ngClass]="{'active show': activeTab === 'story'}" id="story" aria-labelledby="story-tab"><div class="text-center"><div class="about-img mt-5 mb-5"><img src="assets/images/{{aboutData['image']}}.webp" alt="{{aboutData['name']}}" title="{{aboutData['name']}}" class="img-fluid mx-auto rounded-circle site-owner" height="400" width="400" loading="lazy"></div><h3 class="mb-3 wow fadeIn">{{aboutData['name']}} <small class="text-muted"> - {{aboutData['about']['tech-stats']}} </small></h3><p class="text-muted wow slideInUp">{{aboutData["about"]["bio"]}}</p><p class="text-muted wow fadeInDownBig"><strong>IDE, Editors & Tools Used</strong> : {{aboutData['about']['IDE, Editors & Tools'].join(', ')}}</p></div></div><div class="tab-pane fade" [ngClass]="{'active show': activeTab === 'skill'}" id="skill" aria-labelledby="skill-tab"><div class="row"><div class="col-lg-6" *ngFor="let skills of aboutData['skills']"><div class="mt-5" *ngFor="let skillProgress of skills"><p class="text-muted text-uppercase mb-2">{{ skillProgress['skill'] }}</p><div class="progress"><div class="progress-bar" [ngStyle]="{width:skillProgress.progress+'%'}"><div class="progress-value text-muted">{{skillProgress.progress+'%'}}</div></div></div></div></div></div></div><div class="tab-pane fade" [ngClass]="{'active show': activeTab === 'education'}" id="education" aria-labelledby="education-tab"><div class="row"><div class="col-lg-12"><div class="education-section"><i class="fas fa-graduation-cap mt-5 font-size-50"></i><div class="timeline mt-5"><div *ngFor="let ed of aboutData['education']" class="wow timeline-box bounceIn{{ed['animationClass']}}" data-wow-delay="0s"><div class="timeline-container"><h3 class="experience-designation m-0 text-{{ed['textAlignment']}}">{{ed['degree']}}</h3><h4 class="experience-company-name text-{{ed['textAlignment']}}">{{ed['college']}}</h4><h5 class="experience-duration m-0 text-{{ed['textAlignment']}}">{{ed['duration']}}</h5><h6 class="experience-description font-weight-normal text-{{ed['textAlignment']}}">{{ed['percentage']}}</h6></div></div><div id="timeline-divider"><div class="timeline-traveller"><i class="fas fa-plane font-size-25"></i></div></div></div></div></div></div></div></div></div></div></section>
